{
  "name": "AudioNook",
  "description": "A seamless, offline-capable audiobook player that remembers where you left off. Import books, manage your library, and listen with advanced playback controls."
}

export interface Book {
  id: string;
  title: string;
  author?: string;
  coverImage?: string; // Base64 or Blob URL
  addedAt: number;
  lastPlayedAt: number;
  totalChapters: number;
}

export interface Chapter {
  id: string;
  bookId: string;
  index: number;
  title: string;
  fileName: string;
  duration?: number;
  fileBlob: Blob; // Stored in IndexedDB
}

export interface PlaybackState {
  bookId: string | null;
  chapterIndex: number;
  currentTime: number;
  playbackRate: number;
}

export interface Bookmark {
  id: string;
  bookId: string;
  chapterIndex: number;
  timestamp: number;
  note: string;
  createdAt: number;
}

import { Book, Chapter, PlaybackState, Bookmark } from '../types';

const DB_NAME = 'AudioNookDB';
const DB_VERSION = 1;

export const STORES = {
  BOOKS: 'books',
  CHAPTERS: 'chapters', // This will store large blobs
  PLAYBACK: 'playback',
  BOOKMARKS: 'bookmarks'
};

const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onerror = () => reject(request.error);
    request.onsuccess = () => resolve(request.result);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;

      if (!db.objectStoreNames.contains(STORES.BOOKS)) {
        db.createObjectStore(STORES.BOOKS, { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains(STORES.CHAPTERS)) {
        const store = db.createObjectStore(STORES.CHAPTERS, { keyPath: 'id' });
        store.createIndex('bookId', 'bookId', { unique: false });
        store.createIndex('bookId_index', ['bookId', 'index'], { unique: true });
      }
      if (!db.objectStoreNames.contains(STORES.PLAYBACK)) {
        db.createObjectStore(STORES.PLAYBACK, { keyPath: 'bookId' });
      }
      if (!db.objectStoreNames.contains(STORES.BOOKMARKS)) {
        const store = db.createObjectStore(STORES.BOOKMARKS, { keyPath: 'id' });
        store.createIndex('bookId', 'bookId', { unique: false });
      }
    };
  });
};

export const db = {
  async addBook(book: Book, chapters: Chapter[]) {
    const db = await openDB();
    const tx = db.transaction([STORES.BOOKS, STORES.CHAPTERS], 'readwrite');

    await new Promise<void>((resolve, reject) => {
      tx.oncomplete = () => resolve();
      tx.onerror = () => reject(tx.error);
      tx.objectStore(STORES.BOOKS).put(book);
      chapters.forEach(chapter => {
        tx.objectStore(STORES.CHAPTERS).put(chapter);
      });
    });
  },

  async getBooks(): Promise<Book[]> {
    const db = await openDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORES.BOOKS, 'readonly');
      const request = tx.objectStore(STORES.BOOKS).getAll();
      request.onsuccess = () => {
        // Sort by lastPlayedAt descending
        const books = request.result as Book[];
        resolve(books.sort((a, b) => b.lastPlayedAt - a.lastPlayedAt));
      };
      request.onerror = () => reject(request.error);
    });
  },

  async getChapters(bookId: string): Promise<Chapter[]> {
    const db = await openDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORES.CHAPTERS, 'readonly');
      const index = tx.objectStore(STORES.CHAPTERS).index('bookId');
      const request = index.getAll(bookId);
      request.onsuccess = () => {
        const chapters = request.result as Chapter[];
        resolve(chapters.sort((a, b) => a.index - b.index));
      };
      request.onerror = () => reject(request.error);
    });
  },

  async getChapterBlob(bookId: string, index: number): Promise<Blob | null> {
      const db = await openDB();
      return new Promise((resolve, reject) => {
          const tx = db.transaction(STORES.CHAPTERS, 'readonly');
          const storeIndex = tx.objectStore(STORES.CHAPTERS).index('bookId_index');
          const request = storeIndex.get([bookId, index]);
          request.onsuccess = () => resolve(request.result?.fileBlob || null);
          request.onerror = () => reject(request.error);
      });
  },

  async saveProgress(state: PlaybackState) {
    if (!state.bookId) return;
    const db = await openDB();
    const tx = db.transaction([STORES.PLAYBACK, STORES.BOOKS], 'readwrite');

    tx.objectStore(STORES.PLAYBACK).put(state);

    // Update last played timestamp on book
    const bookStore = tx.objectStore(STORES.BOOKS);
    const bookReq = bookStore.get(state.bookId);

    bookReq.onsuccess = () => {
        const book = bookReq.result;
        if (book) {
            book.lastPlayedAt = Date.now();
            bookStore.put(book);
        }
    };
  },

  async getProgress(bookId: string): Promise<PlaybackState | undefined> {
    const db = await openDB();
    return new Promise((resolve, reject) => {
      const tx = db.transaction(STORES.PLAYBACK, 'readonly');
      const request = tx.objectStore(STORES.PLAYBACK).get(bookId);
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  },

  async addBookmark(bookmark: Bookmark) {
    const db = await openDB();
    return new Promise<void>((resolve, reject) => {
        const tx = db.transaction(STORES.BOOKMARKS, 'readwrite');
        tx.objectStore(STORES.BOOKMARKS).put(bookmark);
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
    });
  },

  async getBookmarks(bookId: string): Promise<Bookmark[]> {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(STORES.BOOKMARKS, 'readonly');
        const index = tx.objectStore(STORES.BOOKMARKS).index('bookId');
        const request = index.getAll(bookId);
        request.onsuccess = () => resolve((request.result as Bookmark[]).sort((a, b) => a.timestamp - b.timestamp));
        request.onerror = () => reject(request.error);
    });
  },

  async deleteBook(bookId: string) {
    const db = await openDB();
    const tx = db.transaction([STORES.BOOKS, STORES.CHAPTERS, STORES.PLAYBACK, STORES.BOOKMARKS], 'readwrite');

    // Delete book metadata
    tx.objectStore(STORES.BOOKS).delete(bookId);
    tx.objectStore(STORES.PLAYBACK).delete(bookId);

    // Delete chapters (Need to find keys first or use cursor, but for now simple range deletion if key was compound would be easier, 
    // but since we index by bookId, we can just iterate and delete. 
    // Optimization: Just clear from index? No, need to delete actual records.)
    // For simplicity in this example, we iterate.
    const chapterStore = tx.objectStore(STORES.CHAPTERS);
    const chapterIndex = chapterStore.index('bookId');
    const chapterReq = chapterIndex.getAllKeys(bookId);

    chapterReq.onsuccess = () => {
        chapterReq.result.forEach(key => {
            chapterStore.delete(key);
        });
    };

    const bookmarkStore = tx.objectStore(STORES.BOOKMARKS);
    const bookmarkIndex = bookmarkStore.index('bookId');
    const bookmarkReq = bookmarkIndex.getAllKeys(bookId);

    bookmarkReq.onsuccess = () => {
        bookmarkReq.result.forEach(key => {
            bookmarkStore.delete(key);
        });
    };

    return new Promise<void>((resolve, reject) => {
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
    });
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost' | 'danger';
  size?: 'sm' | 'md' | 'lg' | 'icon';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  className = '', 
  isLoading,
  disabled,
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-xl font-medium transition-all focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900 disabled:opacity-50 disabled:pointer-events-none";

  const variants = {
    primary: "bg-brand-600 text-white hover:bg-brand-500 focus:ring-brand-500 shadow-lg shadow-brand-900/20",
    secondary: "bg-slate-800 text-slate-200 hover:bg-slate-700 focus:ring-slate-600 border border-slate-700",
    ghost: "bg-transparent text-slate-400 hover:text-white hover:bg-slate-800/50",
    danger: "bg-red-500/10 text-red-400 hover:bg-red-500/20 border border-red-500/20"
  };

  const sizes = {
    sm: "px-3 py-1.5 text-sm",
    md: "px-4 py-2 text-base",
    lg: "px-6 py-3 text-lg",
    icon: "p-2"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      ) : null}
      {children}
    </button>
  );
};

import React, { useRef, useState } from 'react';
import { Upload, FolderPlus, Loader2 } from 'lucide-react';
import { db } from '../services/db';
import { v4 as uuidv4 } from 'uuid';
import { Book, Chapter } from '../types';
import { Button } from './Button';

interface FileImporterProps {
  onImportComplete: () => void;
}

export const FileImporter: React.FC<FileImporterProps> = ({ onImportComplete }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const files = event.target.files;
    if (!files || files.length === 0) return;

    setIsProcessing(true);

    try {
      // Group files by potential book (simple logic: all selected files belong to one book for now)
      // In a more complex app, we'd try to parse folder structures or ID3 tags.

      const audioFiles = Array.from(files).filter(f => f.type.startsWith('audio/') || f.name.match(/\.(mp3|m4b|aac|wav|ogg)$/i)).sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));

      if (audioFiles.length === 0) {
        alert("No audio files found in selection.");
        setIsProcessing(false);
        return;
      }

      // Create Book Metadata
      const bookId = uuidv4();
      // Use directory name if available, else first file name
      // webkitRelativePath might be available if folder selection was used
      const dirPath = audioFiles[0].webkitRelativePath;
      const title = dirPath ? dirPath.split('/')[0] : audioFiles[0].name.replace(/\.[^/.]+$/, "");

      const newBook: Book = {
        id: bookId,
        title: title,
        addedAt: Date.now(),
        lastPlayedAt: Date.now(),
        totalChapters: audioFiles.length,
      };

      const chapters: Chapter[] = audioFiles.map((file, index) => ({
        id: uuidv4(),
        bookId: bookId,
        index: index,
        title: file.name,
        fileName: file.name,
        fileBlob: file
      }));

      await db.addBook(newBook, chapters);
      onImportComplete();
    } catch (error) {
      console.error("Import failed", error);
      alert("Failed to import book. Storage might be full.");
    } finally {
      setIsProcessing(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  return (
    <div className="flex flex-col items-center justify-center p-8 border-2 border-dashed border-slate-700 rounded-2xl bg-slate-900/50 hover:bg-slate-800/50 transition-colors">
      <input 
        type="file" 
        multiple 
        accept="audio/*" 
        ref={fileInputRef} 
        onChange={handleFileSelect} 
        className="hidden" 
        id="file-upload"
      />

      <div className="mb-4 p-4 bg-brand-500/10 rounded-full">
        {isProcessing ? (
           <Loader2 className="w-8 h-8 text-brand-400 animate-spin" />
        ) : (
           <FolderPlus className="w-8 h-8 text-brand-400" />
        )}
      </div>

      <h3 className="text-lg font-semibold mb-2">Add New Audiobook</h3>
      <p className="text-slate-400 text-center text-sm mb-6 max-w-xs">
        Select multiple audio files to create a book. We support MP3, M4B, WAV.
      </p>

      <Button 
        onClick={() => fileInputRef.current?.click()} 
        isLoading={isProcessing}
        variant="primary"
      >
        Select Files
      </Button>
    </div>
  );
};

import React from 'react';
import { Play, Pause, SkipBack, SkipForward, Rewind, FastForward } from 'lucide-react';
import { Button } from './Button';

interface PlayerControlsProps {
  isPlaying: boolean;
  onPlayPause: () => void;
  onNext: () => void;
  onPrev: () => void;
  onSeekRewind: () => void;
  onSeekForward: () => void;
  playbackRate: number;
  onRateChange: () => void;
}

export const PlayerControls: React.FC<PlayerControlsProps> = ({
  isPlaying,
  onPlayPause,
  onNext,
  onPrev,
  onSeekRewind,
  onSeekForward,
  playbackRate,
  onRateChange
}) => {
  return (
    <div className="flex flex-col items-center gap-6 w-full max-w-md mx-auto">
      {/* Primary Controls */}
      <div className="flex items-center justify-center gap-6">
        <button 
            onClick={onPrev}
            className="text-slate-400 hover:text-white transition-colors"
            aria-label="Previous Chapter"
        >
            <SkipBack className="w-6 h-6" />
        </button>

        <button 
            onClick={onSeekRewind}
            className="text-slate-300 hover:text-white transition-colors p-2 rounded-full hover:bg-slate-800"
            aria-label="Rewind 15s"
        >
            <Rewind className="w-8 h-8" />
        </button>

        <button 
            onClick={onPlayPause}
            className="bg-brand-500 hover:bg-brand-400 text-white rounded-full p-5 shadow-lg shadow-brand-500/30 transition-all active:scale-95"
            aria-label={isPlaying ? "Pause" : "Play"}
        >
            {isPlaying ? (
                <Pause className="w-8 h-8 fill-current" />
            ) : (
                <Play className="w-8 h-8 fill-current ml-1" />
            )}
        </button>

        <button 
            onClick={onSeekForward}
            className="text-slate-300 hover:text-white transition-colors p-2 rounded-full hover:bg-slate-800"
            aria-label="Forward 30s"
        >
            <FastForward className="w-8 h-8" />
        </button>

         <button 
            onClick={onNext}
            className="text-slate-400 hover:text-white transition-colors"
            aria-label="Next Chapter"
        >
            <SkipForward className="w-6 h-6" />
        </button>
      </div>

      {/* Secondary Controls */}
      <div className="flex items-center gap-4">
        <button 
            onClick={onRateChange}
            className="text-xs font-bold px-3 py-1.5 rounded-lg bg-slate-800 text-brand-300 hover:bg-slate-700 transition-colors"
        >
            {playbackRate}x
        </button>
      </div>
    </div>
  );
};

